-- VIP subscription flag and key-generation support.
alter table public.coach_player_links add column if not exists is_vip boolean not null default false;

create or replace function public.coach_create_unclaimed_key(p_end_date date,p_is_vip boolean default false) returns public.coach_player_links language plpgsql security definer set search_path=public as $$declare v_key text;v_link coach_player_links;begin if auth_role()<>'coach' then raise exception 'Access denied';end if;if p_end_date<=current_date then raise exception 'End date must be in the future';end if;v_key:=upper(substring(replace(gen_random_uuid()::text,'-',''),1,20));insert into coach_player_links(coach_id,player_id,subscription_key,subscription_end_date,status,is_vip)values((select auth.uid()),null,v_key,p_end_date,'active',p_is_vip)returning * into v_link;return v_link;end$$;
create or replace function public.coach_create_player_key(p_player_id uuid,p_end_date date,p_is_vip boolean default false) returns public.coach_player_links language plpgsql security definer set search_path=public as $$declare v_key text;v_link coach_player_links;begin if auth_role()<>'coach' then raise exception 'Access denied';end if;if p_end_date<=current_date then raise exception 'End date must be in the future';end if;v_key:=upper(substring(replace(gen_random_uuid()::text,'-',''),1,20));insert into coach_player_links(coach_id,player_id,subscription_key,subscription_end_date,status,is_vip)values((select auth.uid()),p_player_id,v_key,p_end_date,'active',p_is_vip)on conflict(coach_id,player_id)do update set subscription_key=v_key,subscription_end_date=p_end_date,status='active',is_vip=p_is_vip returning * into v_link;return v_link;end$$;
grant execute on function public.coach_create_unclaimed_key(date,boolean) to authenticated;
grant execute on function public.coach_create_player_key(uuid,date,boolean) to authenticated;
